12	/// Returns true iff `url` parses and its host is exactly `expected_host`. Used
13	/// to gate provider-specific behavior (URL rewrite, vendor headers) so a user
14	/// can't accidentally route their bearer token to OpenRouter by typing
15	/// `https://my-proxy.example/openrouter.ai/v1` — substring matching of the
16	/// host name was a credential-redirection footgun.
17	fn host_is(url: &str, expected_host: &str) -> bool {
18	    reqwest::Url::parse(url)
19	        .ok()
20	        .and_then(|u| u.host_str().map(|h| h.to_ascii_lowercase()))
21	        .as_deref()
22	        == Some(expected_host)
23	}
