45	#[derive(Serialize)]
46	struct ChatRequest {
47	    model: String,
48	    messages: Vec<Message>,
49	    stream: bool,
50	    #[serde(skip_serializing_if = "Option::is_none")]
51	    temperature: Option<f32>,
52	    #[serde(skip_serializing_if = "Option::is_none")]
53	    max_tokens: Option<u32>,
54	    #[serde(skip_serializing_if = "Option::is_none")]
55	    top_p: Option<f32>,
56	    #[serde(skip_serializing_if = "Option::is_none")]
57	    frequency_penalty: Option<f32>,
58	    #[serde(skip_serializing_if = "Option::is_none")]
59	    presence_penalty: Option<f32>,
60	    #[serde(skip_serializing_if = "Option::is_none", rename = "stop")]
61	    stop_sequences: Option<Vec<String>>,
62	    /// OpenAI tools array. Each entry is
63	    /// `{"type":"function","function":{"name","description","parameters"}}`.
64	    /// Stored as `serde_json::Value` so we don't couple the wire shape into
65	    /// our type system — `tools.rs` builds these from `ToolDef` at send time.
66	    #[serde(skip_serializing_if = "Option::is_none")]
67	    tools: Option<Vec<serde_json::Value>>,
68	    /// Asks the provider to emit a final `usage` chunk in streaming mode.
69	    /// OpenAI, LM Studio, and recent vLLM/Ollama gate streaming `usage`
70	    /// behind this flag; without it the post-response token counter and
71	    /// cost display stay empty. OpenRouter emits usage either way, so this
72	    /// is additive across providers.
73	    #[serde(skip_serializing_if = "Option::is_none")]
74	    stream_options: Option<StreamOptions>,
75	}
