89	pub struct Usage {
90	    pub prompt_tokens: Option<u32>,
91	    pub completion_tokens: Option<u32>,
92	    pub total_tokens: Option<u32>,
93	    /// OpenRouter returns `cost` inside the `usage` object (credits charged)
94	    pub cost: Option<f64>,
95	}
