102	#[derive(Deserialize)]
103	struct Delta {
104	    content: Option<String>,
105	    /// Some providers (DeepSeek, OpenRouter forwarding reasoning models) emit a
106	    /// separate `reasoning` field for chain-of-thought. We surface it as a
107	    /// `Reasoning` event so the UI can show it collapsed.
108	    reasoning: Option<String>,
109	    /// Tool call deltas — OpenAI streams tool_calls piecewise across chunks
110	    /// indexed by slot. We accumulate them here in api.rs and emit a single
111	    /// `ToolCalls` event with the assembled list at end-of-stream.
112	    tool_calls: Option<Vec<ToolCallDelta>>,
113	}
114	
115	#[derive(Deserialize)]
116	struct ToolCallDelta {
117	    /// Slot index — multiple tool calls in one assistant turn each get a
118	    /// stable slot, even though their fields trickle in across chunks.
119	    index: usize,
120	    id: Option<String>,
121	    /// Always `"function"` today; we don't surface it because there's only
122	    /// one variant. Allow-dead so the deserializer accepts the field.
123	    #[allow(dead_code)]
124	    #[serde(rename = "type")]
125	    call_type: Option<String>,
126	    function: Option<FunctionDelta>,
127	}
