136	pub enum StreamEvent {
137	    Token(String),
138	    /// Reasoning/thinking text from a separate provider field. Distinct from
139	    /// `Token` so the UI can render it differently. For inline `<think>` tags
140	    /// inside content, the UI parses the assembled text itself.
141	    Reasoning(String),
142	    /// The complete list of tool calls the model emitted in this turn,
143	    /// assembled from per-chunk deltas. Sent before `Done` if any tool
144	    /// calls happened. The app assigns these to the streaming assistant
145	    /// message, then runs them after `Done`.
146	    ToolCalls(Vec<ToolCall>),
147	    Done,
148	    Error(String),
149	    UsageInfo(Usage),
150	    /// `url` is the endpoint the fetch was started against. The receiver
151	    /// validates it still matches the currently-selected endpoint before
152	    /// applying — without that check, switching endpoints while a fetch is
153	    /// in flight could populate the new endpoint with the old endpoint's
154	    /// model list.
155	    ModelsLoaded {
156	        url: String,
157	        models: Vec<String>,
158	    },
159	}
160	
161	const MAX_ERROR_BODY: usize = 4096;
162	const MAX_STREAM_BUFFER: usize = 1024 * 1024; // 1MB
163	
164	/// Returned when an endpoint is reachable but lists zero models. The two
165	/// common causes (LM Studio with no loaded model, Ollama with nothing
166	/// pulled) have different fixes, so surface both rather than guess which
167	/// provider the user is on.
168	const NO_MODELS_HINT: &str = "No models available at this endpoint. \
169	    For LM Studio: load a model in the Developer tab and start the server. \
170	    For Ollama: run `ollama pull <model>`.";
171	
172	pub async fn fetch_models(base_url: &str, api_key: Option<&str>) -> Result<Vec<String>, String> {
173	    let client = Client::builder()
174	        .timeout(REQUEST_TIMEOUT)
175	        .connect_timeout(CONNECT_TIMEOUT)
176	        .build()
177	        .map_err(|e| format!("Failed to create HTTP client: {e}"))?;
178	
179	    let mut url = base_url.trim_end_matches('/').to_string();
180	
181	    // Auto-fix OpenRouter URLs (users often provide just the domain or the
182	    // completions endpoint). Only rewrite when the URL's host is literally
183	    // openrouter.ai — substring matching would let `evil.com/openrouter.ai`
184	    // hijack the rewrite and leak the bearer token.
185	    let is_openrouter = host_is(&url, "openrouter.ai");
186	    if is_openrouter {
187	        url = "https://openrouter.ai/api/v1".to_string();
188	    } else if url.ends_with("/chat/completions") {
189	        url = url.trim_end_matches("/chat/completions").to_string();
190	    }
191	
192	    // Try OpenAI-standard /v1/models first (works for OpenRouter, LM Studio, vLLM, etc.)
193	    let models_url = if url.ends_with("/v1") {
194	        format!("{url}/models")
195	    } else {
196	        format!("{url}/v1/models")
197	    };
198	
199	    let mut request = client.get(&models_url);
200	    if let Some(key) = api_key {
201	        request = request.bearer_auth(key);
202	    }
203	    if is_openrouter {
204	        request = request
205	            .header("HTTP-Referer", "https://github.com/hhheath/hChat")
206	            .header("X-Title", "hChat");
207	    }
208	
209	    // Track "200 with empty data" separately from "didn't respond at all" so
210	    // we can tell LM-Studio-with-no-model-loaded (helpful hint) apart from
211	    // server-not-running (raw connection error).
212	    let mut openai_responded_empty = false;
213	    if let Ok(resp) = request.send().await {
214	        if resp.status().is_success() {
215	            if let Ok(openai_resp) = resp.json::<OpenAIModelsResponse>().await {
216	                let models: Vec<String> = openai_resp.data.into_iter().map(|m| m.id).collect();
217	                if !models.is_empty() {
218	                    return Ok(models);
219	                }
220	                openai_responded_empty = true;
221	            }
222	        }
223	    }
224	
225	    // Fall back to Ollama /api/tags
226	    let api_base = url.trim_end_matches("/v1");
227	    let tags_result: Result<Vec<String>, String> =
228	        match client.get(format!("{api_base}/api/tags")).send().await {
229	            Ok(r) if r.status().is_success() => r
230	                .json::<OllamaTagsResponse>()
231	                .await
232	                .map(|t| t.models.into_iter().map(|m| m.name).collect())
233	                .map_err(|e| format!("Failed to parse models: {e}")),
234	            Ok(r) => Err(format!("Models endpoint returned {}", r.status())),
235	            Err(e) => Err(format!("Failed to fetch models: {e}")),
236	        };
237	
238	    match tags_result {
239	        Ok(m) if !m.is_empty() => Ok(m),
240	        // Ollama path returned an empty list (server reachable, nothing
241	        // pulled) — surface the actionable hint, not a silent empty dropdown.
242	        Ok(_) => Err(NO_MODELS_HINT.to_string()),
243	        // Ollama path errored but OpenAI returned 200 with empty data — this
244	        // is the LM-Studio-no-model-loaded case. Use the hint instead of the
245	        // raw Ollama parse/404 error, which would be misleading.
246	        Err(_) if openai_responded_empty => Err(NO_MODELS_HINT.to_string()),
247	        Err(e) => Err(e),
248	    }
249	}
