251	pub struct ChatParams {
252	    pub base_url: String,
253	    pub model: String,
254	    pub messages: Vec<Message>,
255	    pub temperature: Option<f32>,
256	    pub max_tokens: Option<u32>,
257	    pub top_p: Option<f32>,
258	    pub frequency_penalty: Option<f32>,
259	    pub presence_penalty: Option<f32>,
260	    pub stop_sequences: Option<Vec<String>>,
261	    pub api_key: Option<String>,
262	    /// OpenAI tools array. None = no tool calling for this turn.
263	    pub tools: Option<Vec<serde_json::Value>>,
264	}
265	
266	pub fn stream_chat(
267	    params: ChatParams,
268	    tx: mpsc::UnboundedSender<StreamEvent>,
269	    cancel: CancellationToken,
270	) {
271	    tokio::spawn(async move {
272	        let ChatParams {
273	            base_url,
274	            model,
275	            messages,
276	            temperature,
277	            max_tokens,
278	            top_p,
279	            frequency_penalty,
280	            presence_penalty,
281	            stop_sequences,
282	            api_key,
283	            tools,
284	        } = params;
285	        let client = match Client::builder().connect_timeout(CONNECT_TIMEOUT).build() {
286	            Ok(c) => c,
287	            Err(e) => {
288	                let _ = tx.send(StreamEvent::Error(format!(
289	                    "Failed to create HTTP client: {e}"
290	                )));
291	                return;
292	            }
293	        };
294	        let mut base_url = base_url.trim_end_matches('/').to_string();
295	
296	        let is_openrouter = host_is(&base_url, "openrouter.ai");
297	        if is_openrouter {
298	            base_url = "https://openrouter.ai/api/v1".to_string();
299	        } else if base_url.ends_with("/chat/completions") {
300	            base_url = base_url.trim_end_matches("/chat/completions").to_string();
301	        }
302	
303	        let url = format!("{}/chat/completions", base_url);
304	
305	        let req = ChatRequest {
306	            model,
307	            messages,
308	            stream: true,
309	            temperature,
310	            max_tokens,
311	            top_p,
312	            frequency_penalty,
313	            presence_penalty,
314	            stop_sequences,
315	            tools,
316	            stream_options: Some(StreamOptions {
317	                include_usage: true,
318	            }),
319	        };
320	
321	        let mut request = client.post(&url).json(&req);
322	        if let Some(key) = &api_key {
323	            request = request.bearer_auth(key);
324	        }
325	        if is_openrouter {
326	            request = request
327	                .header("HTTP-Referer", "https://github.com/hhheath/hChat")
328	                .header("X-Title", "hChat");
329	        }
330	
331	        let resp = match request.send().await {
332	            Ok(r) => r,
333	            Err(e) => {
334	                let _ = tx.send(StreamEvent::Error(format!("Request failed: {e}")));
335	                return;
336	            }
337	        };
338	
339	        if !resp.status().is_success() {
340	            let status = resp.status();
341	            let body = resp
342	                .bytes()
343	                .await
344	                .map(|b| {
345	                    let truncated = &b[..b.len().min(MAX_ERROR_BODY)];
346	                    String::from_utf8_lossy(truncated).into_owned()
347	                })
348	                .unwrap_or_default();
349	            // Log full error for debugging but only show sanitized message in UI
350	            eprintln!("API error {status}: {body}");
351	            let message = match status.as_u16() {
352	                401 => format!("{status}: Authentication failed — check your API key"),
353	                403 => format!("{status}: Access denied"),
354	                404 => format!("{status}: Endpoint not found — check your URL"),
355	                429 => format!("{status}: Rate limited — try again later"),
356	                500..=599 => format!("{status}: Server error"),
357	                _ => format!("{status}: Request failed"),
358	            };
359	            let _ = tx.send(StreamEvent::Error(message));
360	            return;
361	        }
362	
363	        let mut stream = resp.bytes_stream();
364	        // Use a byte buffer to handle UTF-8 sequences split across chunks
365	        let mut raw_buf: Vec<u8> = Vec::new();
366	
367	        // Tool call accumulator: index → (id, name, arguments-so-far). We
368	        // assemble per-slot across deltas and emit a single ToolCalls event
369	        // before Done. Using a Vec<Option<_>> keyed by index handles sparse
370	        // / out-of-order deltas without allocating a HashMap for what's
371	        // typically 1–3 calls.
372	        let mut tool_acc: Vec<Option<(Option<String>, String, String)>> = Vec::new();
373	
374	        loop {
375	            tokio::select! {
376	                _ = cancel.cancelled() => {
377	                    flush_tool_calls(&mut tool_acc, &tx);
378	                    let _ = tx.send(StreamEvent::Done);
379	                    return;
380	                }
381	                chunk = stream.next() => {
382	                    let Some(chunk) = chunk else {
383	                        flush_tool_calls(&mut tool_acc, &tx);
384	                        let _ = tx.send(StreamEvent::Done);
385	                        return;
386	                    };
387	
388	                    let bytes = match chunk {
389	                        Ok(b) => b,
390	                        Err(e) => {
391	                            let _ = tx.send(StreamEvent::Error(format!("Stream error: {e}")));
392	                            return;
393	                        }
394	                    };
395	
396	                    if raw_buf.len() + bytes.len() > MAX_STREAM_BUFFER {
397	                        let _ = tx.send(StreamEvent::Error("Stream buffer overflow".to_string()));
398	                        return;
399	                    }
400	
401	                    raw_buf.extend_from_slice(&bytes);
402	
403	                    // Find the last valid UTF-8 boundary to avoid splitting multi-byte chars
404	                    let valid_up_to = match std::str::from_utf8(&raw_buf) {
405	                        Ok(_) => raw_buf.len(),
406	                        Err(e) => e.valid_up_to(),
407	                    };
408	
409	                    if valid_up_to == 0 {
410	                        continue;
411	                    }
412	
413	                    // Safe: we just validated this range is valid UTF-8
414	                    let text = std::str::from_utf8(&raw_buf[..valid_up_to]).unwrap();
415	                    let mut remaining_start = 0;
416	
417	                    for line_end in newline_positions(text) {
418	                        let line = text[remaining_start..line_end].trim();
419	                        remaining_start = line_end + 1;
420	
421	                        if line.is_empty() || line.starts_with(':') {
422	                            continue;
423	                        }
424	
425	                        let data = if let Some(d) = line.strip_prefix("data: ") {
426	                            d.trim()
427	                        } else {
428	                            continue;
429	                        };
430	
431	                        if data == "[DONE]" {
432	                            flush_tool_calls(&mut tool_acc, &tx);
433	                            let _ = tx.send(StreamEvent::Done);
434	                            return;
435	                        }
436	
437	                        if let Ok(chunk) = serde_json::from_str::<ChatChunk>(data) {
438	                            if let Some(choices) = chunk.choices {
439	                                for choice in choices {
440	                                    if let Some(delta) = choice.delta {
441	                                        // Skip empty strings: some providers
442	                                        // (Ollama qwen3 thinking, OpenAI keep-
443	                                        // alives) emit `content: ""` alongside
444	                                        // a reasoning delta. Treating that as
445	                                        // "content arrived" prematurely closes
446	                                        // the <think> block and the next
447	                                        // reasoning delta re-opens a new one,
448	                                        // producing dozens of tiny blocks.
449	                                        if let Some(reasoning) = delta.reasoning
450	                                            && !reasoning.is_empty()
451	                                        {
452	                                            let _ = tx.send(StreamEvent::Reasoning(reasoning));
453	                                        }
454	                                        if let Some(content) = delta.content
455	                                            && !content.is_empty()
456	                                        {
457	                                            let _ = tx.send(StreamEvent::Token(content));
458	                                        }
459	                                        if let Some(tcds) = delta.tool_calls {
460	                                            for tcd in tcds {
461	                                                accumulate_tool_call(&mut tool_acc, tcd);
462	                                            }
463	                                        }
464	                                    }
465	                                }
466	                            }
467	                            if let Some(usage) = chunk.usage {
468	                                let _ = tx.send(StreamEvent::UsageInfo(usage));
469	                            }
470	                        }
471	                    }
472	
473	                    // Keep unprocessed bytes (incomplete line + any trailing invalid UTF-8)
474	                    let consumed = remaining_start.min(valid_up_to);
475	                    raw_buf = raw_buf[consumed..].to_vec();
476	                }
477	            }
478	        }
479	    });
480	}
481	
482	/// Append a streaming `ToolCallDelta` into the accumulator. The accumulator
483	/// is keyed by the slot `index` so out-of-order deltas across chunks land
484	/// in the right slot. `id` and `name` arrive once each (usually in the
485	/// first delta for a slot); `arguments` is concatenated piecewise.
486	fn accumulate_tool_call(
487	    acc: &mut Vec<Option<(Option<String>, String, String)>>,
488	    d: ToolCallDelta,
489	) {
490	    while acc.len() <= d.index {
491	        acc.push(None);
492	    }
493	    let slot = acc[d.index].get_or_insert_with(|| (None, String::new(), String::new()));
494	    if let Some(id) = d.id {
495	        slot.0 = Some(id);
496	    }
497	    if let Some(f) = d.function {
498	        if let Some(name) = f.name {
499	            slot.1 = name;
500	        }
501	        if let Some(args) = f.arguments {
502	            slot.2.push_str(&args);
503	        }
504	    }
505	}
506	
507	/// Drain the accumulator into a final `ToolCalls` event. Slots missing an
508	/// id are dropped (and logged) — without an id we can't match a result
509	/// back. No-op if no calls were accumulated, so emitting unconditionally
510	/// before Done is safe.
511	fn flush_tool_calls(
512	    acc: &mut Vec<Option<(Option<String>, String, String)>>,
513	    tx: &mpsc::UnboundedSender<StreamEvent>,
514	) {
515	    let calls: Vec<ToolCall> = acc
516	        .drain(..)
517	        .enumerate()
518	        .filter_map(|(slot_idx, slot)| {
519	            let (id, name, args) = slot?;
520	            let Some(id) = id else {
521	                // The model thinks it called this tool; we'd be telling it
522	                // nothing came back. Surface a diagnostic so the dropped
523	                // call is at least debuggable.
524	                eprintln!(
525	                    "tool_call slot {slot_idx} ('{name}') arrived without an id — dropping"
526	                );
527	                return None;
528	            };
529	            Some(ToolCall {
530	                id,
531	                call_type: "function".to_string(),
532	                function: ToolCallFunction {
533	                    name,
534	                    arguments: args,
535	                },
536	            })
537	        })
538	        .collect();
539	    if !calls.is_empty() {
540	        let _ = tx.send(StreamEvent::ToolCalls(calls));
541	    }
542	}
543	
544	/// Find all newline positions in a string slice
545	fn newline_positions(s: &str) -> impl Iterator<Item = usize> + '_ {
546	    s.bytes()
547	        .enumerate()
548	        .filter_map(|(i, b)| if b == b'\n' { Some(i) } else { None })
549	}
