580	pub async fn complete_once(
581	    base_url: &str,
582	    model: &str,
583	    messages: &[Message],
584	    api_key: Option<&str>,
585	    max_tokens: Option<u32>,
586	    temperature: Option<f32>,
587	) -> Result<String, String> {
588	    let client = Client::builder()
589	        .timeout(REQUEST_TIMEOUT)
590	        .connect_timeout(CONNECT_TIMEOUT)
591	        .build()
592	        .map_err(|e| format!("Failed to create HTTP client: {e}"))?;
593	
594	    let mut base_url = base_url.trim_end_matches('/').to_string();
595	    let is_openrouter = host_is(&base_url, "openrouter.ai");
596	    if is_openrouter {
597	        base_url = "https://openrouter.ai/api/v1".to_string();
598	    } else if base_url.ends_with("/chat/completions") {
599	        base_url = base_url.trim_end_matches("/chat/completions").to_string();
600	    }
601	    let url = format!("{}/chat/completions", base_url);
602	
603	    let req = NonStreamingChatRequest {
604	        model,
605	        messages,
606	        stream: false,
607	        max_tokens,
608	        temperature,
609	    };
610	
611	    let mut request = client.post(&url).json(&req);
612	    if let Some(key) = api_key {
613	        request = request.bearer_auth(key);
614	    }
615	    if is_openrouter {
616	        request = request
617	            .header("HTTP-Referer", "https://github.com/hhheath/hChat")
618	            .header("X-Title", "hChat");
619	    }
620	
621	    let resp = request
622	        .send()
623	        .await
624	        .map_err(|e| format!("Request failed: {e}"))?;
625	    if !resp.status().is_success() {
626	        let status = resp.status();
627	        return Err(format!("{status}"));
628	    }
629	    let parsed: NonStreamingChatResponse = resp
630	        .json()
631	        .await
632	        .map_err(|e| format!("Failed to parse response: {e}"))?;
633	    parsed
634	        .choices
635	        .into_iter()
636	        .next()
637	        .and_then(|c| c.message.content)
638	        .ok_or_else(|| "Empty response".to_string())
