use crate::message::{ContentPart, Message, Role};
use rusqlite::{Connection, params};
use std::path::PathBuf;
use std::time::Duration;

/// Returned by `list_conversations`: enough to render the sidebar (pinned-first
/// sort, optional pin-marker glyph) without a second query per row.
pub struct Conversation {
    pub id: i64,
    pub title: String,
    pub pinned: bool,
}

/// Per-conversation settings snapshot. All fields are `Option` because a
/// conversation may have been created before any setting was customized
/// (column NULL → use the global default).
#[derive(Clone, Debug, Default)]
pub struct ConversationSettings {
    pub model: Option<String>,
    pub system_prompt: Option<String>,
    pub temperature: Option<f32>,
    pub max_tokens: Option<u32>,
    pub use_max_tokens: bool,
    pub top_p: Option<f32>,
    pub frequency_penalty: Option<f32>,
    pub presence_penalty: Option<f32>,
    pub stop_sequences: Vec<String>,
    pub endpoint: Option<String>,
    /// Working directory for tool calls in this conversation. `None` falls
    /// back to `~`. Set per-conversation via the settings panel.
    pub working_dir: Option<String>,
}

pub struct Storage {
    conn: Connection,
}

impl Storage {
    pub fn new() -> Self {
        let path = Self::db_path();

    }

    pub fn delete_preset(&self, id: i64) {
        self.conn
            .execute("DELETE FROM presets WHERE id = ?1", params![id])
            .ok();
    }
}

#[derive(Clone)]
pub struct Preset {
    pub id: i64,
    pub name: String,
    pub settings: ConversationSettings,
}

/// Lightweight sibling-row description for the navigation UI. Doesn't carry
/// content — just enough to pick the right id and show "N/M".
pub struct MessageHeader {
    pub id: i64,
    /// Persisted branch_index. Not currently read by the UI (the N/M
    /// display uses array position) but exposed for tests / future code.
    #[allow(dead_code)]
    pub branch_index: i64,
    #[allow(dead_code)]
    pub created_at: Option<i64>,
}

/// Raw row from the messages table — we rebuild `Message` from this with
/// the JSON content parse separated out so the load/walk paths don't
/// duplicate parsing logic.
#[derive(Clone)]
struct MessageRow {
    id: i64,
    role: Role,
    content: Vec<ContentPart>,
    created_at: Option<i64>,
    parent_id: Option<i64>,
    branch_index: i64,
    #[allow(dead_code)]
    position: i64,
    tool_calls: Option<Vec<crate::message::ToolCall>>,
    tool_call_id: Option<String>,
}

pub struct ToolDef {
    pub name: String,
    pub description: String,
    /// JSON Schema for the function's parameters. Stored as a free-form
    /// `serde_json::Value` because we don't validate it ourselves — the
    /// LLM provider does. Passes through to the API's `tools[].function.
    /// parameters` field unchanged.
    pub parameters: serde_json::Value,
    pub handler: Handler,
    #[serde(default)]
    pub safety: Safety,
}

/// Two handler shapes:
/// - `handler = "builtin:read_file"` → `Handler::Builtin("read_file")`
///   (the prefix is stripped on parse). Dispatched to native Rust.
/// - `handler = { shell = ["git", "log", "-n", "{{count}}"] }` →
///   `Handler::Shell(...)`. Forked + execed at run time with `{{var}}`
///   placeholders substituted from the call's arguments.
#[derive(Debug, Clone, Deserialize)]
#[serde(untagged)]
pub enum Handler {
    Builtin(BuiltinRef),
    Shell { shell: Vec<String> },
}

#[derive(Debug, Clone)]
pub struct BuiltinRef(pub String);

impl<'de> Deserialize<'de> for BuiltinRef {
    fn deserialize<D: serde::Deserializer<'de>>(d: D) -> Result<Self, D::Error> {
        let s = String::deserialize(d)?;
        match s.strip_prefix("builtin:") {
            Some(name) if !name.is_empty() => Ok(BuiltinRef(name.to_string())),
            _ => Err(serde::de::Error::custom(format!(
                "expected handler = \"builtin:<name>\", got '{s}'"
            ))),
        }
    }
}

#[derive(Debug, Clone, Copy, Default, Deserialize, PartialEq, Eq)]
#[serde(rename_all = "lowercase")]
pub enum Safety {
    /// Execute without prompting. The default — fits read-only tools.
