pub fn run_builtin(
    name: &str,
    args: &serde_json::Value,
    working_dir: &Path,
) -> Result<String, String> {
    match name {
        "read_file" => builtin_read_file(args, working_dir),
        "list_directory" => builtin_list_directory(args, working_dir),
        "search_files" => builtin_search_files(args, working_dir),
        "write_file" => builtin_write_file(args, working_dir),
        "run_shell" => builtin_run_shell(args, working_dir),
        other => Err(format!("unknown builtin tool: {other}")),
    }
}

fn builtin_read_file(args: &serde_json::Value, wd: &Path) -> Result<String, String> {
    let path = resolve_path(arg_str(args, "path")?, wd);
    let offset = args.get("offset").and_then(|v| v.as_u64()).unwrap_or(0);
    let limit = args.get("limit").and_then(|v| v.as_u64());
    let body = std::fs::read_to_string(&path)
        .map_err(|e| format!("read failed: {}: {e}", path.display()))?;

pub fn save_messages(
    &self,
    conversation_id: i64,
    messages: &mut [Message],
) -> Result<(), String> {
    let tx = self
        .conn
        .unchecked_transaction()
        .map_err(|e| format!("Failed to start transaction: {e}"))?;

    // Find the highest existing position so new inserts append rather
    // than collide with existing rows. Position is a tiebreaker for the
    // legacy load path and a stable insertion order.
    let mut next_position: i64 = tx
        .query_row(
            "SELECT COALESCE(MAX(position), -1) FROM messages WHERE conversation_id = ?1",
            params![conversation_id],
            |row| row.get(0),
        )
        .unwrap_or(-1)
        + 1;

    let mut prev_id: Option<i64> = None;
    for msg in messages.iter_mut() {
        let role_str = match msg.role {
            Role::System => "system",
            Role::User => "user",
            Role::Assistant => "assistant",
            Role::Tool => "tool",
        };

