:root {
  --bg: #0c0c0e;
  --panel: #templated;
  --panel: #131315;
  --panel-2: #17171a;
  --panel-3: #1d1d21;
  --border: #26262b;
  --border-soft: #1f1f24;
  --text: #e7e7ea;
  --muted: #8b8b93;
  --dim: #5b5b63;
  --faint: #3a3a40;
  --accent: #38bdb4;
  --accent-dim: #2a8c85;
  --danger: #e5484d;
  --warn: #e2a03f;
  --user: #2563eb;

  --mono: "SF Mono", "JetBrains Mono", "Menlo", ui-monospace, monospace;
  --sans: -apple-system, "Inter", "Segoe UI", system-ui, sans-serif;

  --rail-w: 248px;
}

* {
  box-sizing: border-box;
}

html,
body,
#root {
  height: 100%;
  margin: 0;
}

body {
  background: var(--bg);
  color: var(--text);
  font-family: var(--sans);
  font-size: 14px;
  line-height: 1.55;
  -webkit-font-smoothing: antialiased;
  overflow: hidden;
}

button {
  font-family: inherit;
  color: inherit;
  cursor: pointer;
}

::-webkit-scrollbar {
  width: 9px;
  height: 9px;
}
::-webkit-scrollbar-thumb {
  background: #2a2a30;
  border-radius: 6px;
}
::-webkit-scrollbar-thumb:hover {
  background: #3a3a42;
}
::-webkit-scrollbar-track {
  background: transparent;
}

/* ---------- App shell ---------- */
.app {
  display: grid;
  grid-template-columns: var(--rail-w) 1fr;
  height: 100vh;
  overflow: hidden;
}

/* ---------- Left rail ---------- */
.rail {
  background: #0a0a0c;
  border-right: 1px solid var(--border-soft);
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.rail-search {
  padding: 12px 12px 8px;
}
.rail-search input {
  width: 100%;
  background: var(--panel-2);
