}
.md p {
  margin: 0 0 12px;
}
.md p:last-child {
  margin-bottom: 0;
}
.md h1,
.md h2,
.md h3 {
  margin: 18px 0 8px;
  line-height: 1.3;
}
.md ul,
.md ol {
  margin: 0 0 12px;
  padding-left: 22px;
}
.md li {
  margin: 3px 0;
}
.md a {
  color: var(--accent);
}
.md blockquote {
  border-left: 3px solid var(--border);
  margin: 0 0 12px;
  padding-left: 14px;
  color: var(--muted);
}
