  font-size: 0.88em;
  background: var(--panel-3);
  padding: 1px 5px;
  border-radius: 4px;
}
.md table {
  border-collapse: collapse;
  margin: 0 0 12px;
  font-size: 13px;
}
.md th,
.md td {
  border: 1px solid var(--border);
  padding: 5px 10px;
}

.code-block {
  position: relative;
  margin: 0 0 14px;
  border: 1px solid var(--border-soft);
  border-radius: 8px;
  overflow: hidden;
  background: #0a0a0c;
}
