  border: 1px solid var(--border);
  border-radius: 5px;
  color: var(--muted);
  font-size: 10.5px;
  padding: 2px 7px;
}
.code-block .code-head button:hover {
  color: var(--text);
}
.code-block pre {
  margin: 0;
  padding: 12px 14px;
  overflow-x: auto;
  font-family: var(--mono);
  font-size: 12.5px;
  line-height: 1.55;
}
.code-block pre code {
