  bottom: 18px;
  left: 50%;
  transform: translateX(-50%);
  background: #2a1416;
  border: 1px solid #5a2a2c;
  color: #ffb4b6;
  padding: 9px 16px;
  border-radius: 9px;
  font-size: 13px;
  z-index: 50;
  max-width: 560px;
}

