.status {
  flex: 1;
  overflow-y: auto;
  padding: 8px 28px 40px;
}
.status h1 {
  font-size: 22px;
  font-weight: 600;
  margin: 4px 0 18px;
}
.tiles {
  display: grid;
  grid-template-columns: 1.3fr 1.3fr 1.3fr 0.7fr 1fr 1fr;
  gap: 0;
  border-bottom: 1px solid var(--border-soft);
  padding-bottom: 18px;
}
.tile {
  padding: 0 18px;
  border-left: 1px solid var(--border-soft);
}
.tile:first-child {
  border-left: none;
  padding-left: 0;
}
.tile .label {
  font-size: 10.5px;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--dim);
  margin-bottom: 8px;
}
.tile .value {
  font-family: var(--mono);
  font-size: 32px;
  font-weight: 500;
  letter-spacing: -0.01em;
  line-height: 1;
}
.tile .value .unit {
