  color: var(--muted);
}
.totals .k {
  color: var(--dim);
  letter-spacing: 0.08em;
  text-transform: uppercase;
  margin-right: 8px;
  font-size: 10.5px;
}
.charts {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 24px;
  padding: 22px 0;
}
.chart-card .chart-head {
  display: flex;
  justify-content: space-between;
  font-size: 10.5px;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--dim);
  margin-bottom: 10px;
}
.chart-card .uplot-wrap {
  height: 150px;
}
.gpu-list {
  border-top: 1px solid var(--border-soft);
  padding-top: 16px;
}
.gpu-row {
  display: grid;
  grid-template-columns: 40px 1fr 90px 60px 50px 90px;
  gap: 12px;
  align-items: center;
  font-family: var(--mono);
  font-size: 12px;
  color: var(--muted);
  padding: 5px 0;
}
.logs {
  margin-top: 22px;
  border-top: 1px solid var(--border-soft);
  padding-top: 14px;
}
.logs pre {
  font-family: var(--mono);
  font-size: 11.5px;
  color: var(--dim);
  background: #0a0a0c;
  border: 1px solid var(--border-soft);
  border-radius: 8px;
  padding: 12px;
  max-height: 220px;
  overflow: auto;
  margin: 0;
}

.dashboard-empty {
  color: var(--dim);
  font-size: 13px;
  padding: 40px 0;
}

/* ---------- modal ---------- */
.modal-backdrop {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.55);
  display: grid;
  place-items: center;
  z-index: 40;
}
.modal {
  background: var(--panel);
  border: 1px solid var(--border);
  border-radius: 14px;
  width: 560px;
  max-width: 92vw;
  max-height: 86vh;
  overflow-y: auto;
  padding: 22px 24px;
}
.modal h2 {
  margin: 0 0 16px;
  font-size: 16px;
}
.field {
  margin-bottom: 14px;
}
.field label {
  display: block;
  font-size: 11px;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--dim);
  margin-bottom: 6px;
}
.field input,
.field textarea,
.field select {
  width: 100%;
  background: var(--panel-2);
  border: 1px solid var(--border);
  border-radius: 8px;
  color: var(--text);
  padding: 8px 10px;
  font-size: 13px;
  outline: none;
  font-family: var(--sans);
}
.field input:focus,
.field textarea:focus {
  border-color: var(--accent-dim);
}
.field .row {
  display: flex;
  gap: 12px;
}
.modal-actions {
  display: flex;
  justify-content: flex-end;
  gap: 10px;
  margin-top: 18px;
}
.endpoint-row {
  display: flex;
  gap: 8px;
  align-items: center;
  margin-bottom: 6px;
}
.endpoint-row input {
  flex: 1;
}
.icon-btn {
  background: transparent;
  border: none;
  color: var(--dim);
  font-size: 14px;
  padding: 4px;
}
.icon-btn:hover {
  color: var(--text);
}

