.md {
  font-size: 14.5px;
  line-height: 1.65;
  color: var(--text);
  word-wrap: break-word;
}
.md p {
  margin: 0 0 12px;
}
.md p:last-child {
  margin-bottom: 0;
}
.md h1,
.md h2,
.md h3 {
  margin: 18px 0 8px;
  line-height: 1.3;
}
.md ul,
.md ol {
  margin: 0 0 12px;
  padding-left: 22px;
}
.md li {
  margin: 3px 0;
}
.md a {
  color: var(--accent);
}
.md blockquote {
  border-left: 3px solid var(--border);
  margin: 0 0 12px;
  padding-left: 14px;
  color: var(--muted);
}
.md :not(pre) > code {
  font-family: var(--mono);
  font-size: 0.88em;
  background: var(--panel-3);
  padding: 1px 5px;
  border-radius: 4px;
}
.md table {
  border-collapse: collapse;
  margin: 0 0 12px;
  font-size: 13px;
}
.md th,
.md td {
  border: 1px solid var(--border);
  padding: 5px 10px;
}

.code-block {
  position: relative;
  margin: 0 0 14px;
  border: 1px solid var(--border-soft);
  border-radius: 8px;
  overflow: hidden;
  background: #0a0a0c;
}
.code-block .code-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 5px 10px 5px 12px;
  background: var(--panel);
  border-bottom: 1px solid var(--border-soft);
  font-family: var(--mono);
  font-size: 11px;
  color: var(--dim);
}
.code-block .code-head .acts {
  display: flex;
  gap: 6px;
}
.code-block .code-head button {
  background: transparent;
  border: 1px solid var(--border);
  border-radius: 5px;
  color: var(--muted);
  font-size: 10.5px;
  padding: 2px 7px;
}
.code-block .code-head button:hover {
  color: var(--text);
}
.code-block pre {
  margin: 0;
  padding: 12px 14px;
  overflow-x: auto;
  font-family: var(--mono);
  font-size: 12.5px;
  line-height: 1.55;
}
.code-block pre code {
  font-family: var(--mono);
}

/* ---------- Composer ---------- */
.composer {
  border-top: 1px solid var(--border-soft);
  padding: 14px 24px 18px;
}
.composer-inner {
  max-width: 820px;
  margin: 0 auto;
}
.composer-box {
  border: 1px solid var(--border);
  border-radius: 12px;
  background: var(--panel);
  padding: 10px 12px;
  transition: border-color 0.15s;
}
.composer-box:focus-within {
  border-color: var(--accent-dim);
}
.composer textarea {
  width: 100%;
  background: transparent;
  border: none;
  outline: none;
  resize: none;
  color: var(--text);
  font-family: var(--sans);
  font-size: 14.5px;
  line-height: 1.5;
  max-height: 220px;
}
.composer-row {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-top: 8px;
}
.composer-row .hint {
  font-size: 11px;
  color: var(--dim);
}
.send-btn {
  margin-left: auto;
  background: var(--accent);
  color: #04201d;
  border: none;
  border-radius: 8px;
  padding: 7px 16px;
  font-weight: 600;
  font-size: 13px;
}
.send-btn:hover {
  background: #45cfc5;
}
.send-btn:disabled {
  background: var(--panel-3);
  color: var(--dim);
}
.stop-btn {
  margin-left: auto;
  background: transparent;
  color: var(--danger);
  border: 1px solid #5a2a2c;
  border-radius: 8px;
  padding: 7px 16px;
  font-size: 13px;
}

/* ---------- empty state ---------- */
.empty {
  height: 100%;
  display: grid;
  place-items: center;
  color: var(--dim);
  text-align: center;
}
.empty .glyph {
  font-size: 40px;
  color: var(--accent);
  opacity: 0.5;
  margin-bottom: 12px;
}

/* ---------- error toast ---------- */
.toast {
  position: fixed;
  bottom: 18px;
  left: 50%;
  transform: translateX(-50%);
  background: #2a1416;
  border: 1px solid #5a2a2c;
  color: #ffb4b6;
  padding: 9px 16px;
  border-radius: 9px;
  font-size: 13px;
  z-index: 50;
  max-width: 560px;
}

/* ---------- Status dashboard ---------- */
.status {
  flex: 1;
  overflow-y: auto;
  padding: 8px 28px 40px;
}
.status h1 {
  font-size: 22px;
  font-weight: 600;
  margin: 4px 0 18px;
}
.tiles {
  display: grid;
  grid-template-columns: 1.3fr 1.3fr 1.3fr 0.7fr 1fr 1fr;
  gap: 0;
  border-bottom: 1px solid var(--border-soft);
  padding-bottom: 18px;
}
.tile {
  padding: 0 18px;
  border-left: 1px solid var(--border-soft);
}
.tile:first-child {
  border-left: none;
  padding-left: 0;
}
.tile .label {
  font-size: 10.5px;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--dim);
  margin-bottom: 8px;
}
.tile .value {
  font-family: var(--mono);
  font-size: 32px;
  font-weight: 500;
  letter-spacing: -0.01em;
  line-height: 1;
}
.tile .value .unit {
  font-size: 13px;
  color: var(--muted);
  margin-left: 5px;
  font-weight: 400;
}
.tile .sub {
  font-family: var(--mono);
  font-size: 11px;
  color: var(--dim);
  margin-top: 8px;
}
.totals {
  display: flex;
  gap: 40px;
  padding: 16px 0;
  border-bottom: 1px solid var(--border-soft);
  font-family: var(--mono);
  font-size: 12px;
  color: var(--muted);
}
.totals .k {
  color: var(--dim);
  letter-spacing: 0.08em;
  text-transform: uppercase;
  margin-right: 8px;
  font-size: 10.5px;
}
.charts {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 24px;
  padding: 22px 0;
}
.chart-card .chart-head {
  display: flex;
  justify-content: space-between;
  font-size: 10.5px;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--dim);
  margin-bottom: 10px;
}
.chart-card .uplot-wrap {
  height: 150px;
}
.gpu-list {
  border-top: 1px solid var(--border-soft);
  padding-top: 16px;
}
.gpu-row {
  display: grid;
  grid-template-columns: 40px 1fr 90px 60px 50px 90px;
  gap: 12px;
  align-items: center;
  font-family: var(--mono);
  font-size: 12px;
  color: var(--muted);
  padding: 5px 0;
}
.logs {
  margin-top: 22px;
  border-top: 1px solid var(--border-soft);
  padding-top: 14px;
}
.logs pre {
  font-family: var(--mono);
  font-size: 11.5px;
  color: var(--dim);
  background: #0a0a0c;
  border: 1px solid var(--border-soft);
  border-radius: 8px;
  padding: 12px;
  max-height: 220px;
  overflow: auto;
  margin: 0;
}

.dashboard-empty {
  color: var(--dim);
  font-size: 13px;
  padding: 40px 0;
}

/* ---------- modal ---------- */
.modal-backdrop {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.55);
  display: grid;
  place-items: center;
  z-index: 40;
}
.modal {
  background: var(--panel);
  border: 1px solid var(--border);
  border-radius: 14px;
  width: 560px;
  max-width: 92vw;
  max-height: 86vh;
  overflow-y: auto;
  padding: 22px 24px;
}
.modal h2 {
  margin: 0 0 16px;
  font-size: 16px;
}
.field {
  margin-bottom: 14px;
}
.field label {
  display: block;
  font-size: 11px;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--dim);
  margin-bottom: 6px;
}
.field input,
.field textarea,
.field select {
  width: 100%;
  background: var(--panel-2);
  border: 1px solid var(--border);
  border-radius: 8px;
  color: var(--text);
  padding: 8px 10px;
  font-size: 13px;
  outline: none;
  font-family: var(--sans);
}
.field input:focus,
.field textarea:focus {
  border-color: var(--accent-dim);
}
.field .row {
  display: flex;
  gap: 12px;
}
.modal-actions {
  display: flex;
  justify-content: flex-end;
  gap: 10px;
  margin-top: 18px;
}
.endpoint-row {
  display: flex;
  gap: 8px;
  align-items: center;
  margin-bottom: 6px;
}
.endpoint-row input {
  flex: 1;
}
.icon-btn {
  background: transparent;
  border: none;
  color: var(--dim);
  font-size: 14px;
  padding: 4px;
}
.icon-btn:hover {
  color: var(--text);
}

